// ── Label ZPL ─────────────────────────────────────────────────────────────────

/**
 * Standard label: one or more text lines (auto-positioned), optional QR.
 * @param {string[]} lines       — display text lines
 * @param {string|null} qrValue  — QR code content (null = no QR)
 */
export function generateLabelZPL(lines, qrValue = null) {
  const clean = lines.map(l => l.trim()).filter(Boolean);

  const textCmds = clean.map((line, i) => {
    const y = 50 + i * 40;
    return `^FO10,${y}^FD${line}^FS`;
  }).join('\n');

  let zpl = `^XA\n^PW250\n^LL130\n^CF0,35\n${textCmds}`;

  if (qrValue) {
    zpl += `\n^FO130,0^BQN,2,5\n^FDQA,${qrValue}^FS`;
  }

  zpl += '\n^XZ';
  return zpl;
}

// ── Card ZPL ─────────────────────────────────────────────────────────────────

/**
 * Device card (A5-ish large label) with logo, accessories, QR code.
 * @param {string} serialNumber
 * @param {string} productType
 * @param {string} accessories  — may contain \n newlines
 */
export function generateCardZPL(serialNumber, productType, accessories) {
  const footer1 = 'Eigentum der Tickettoaster event technologies GmbH';
  const footer2 = 'Wolfhager Str. 39a, 34117 Kassel';
  const accEsc  = accessories.replace(/\n/g, '\\&');

  return `^XA
^CI28
^PW800
^LL1200
^CF0,40
^FO50,50^FD${productType} - ${serialNumber}^FS
^FO50,130^FDZubehör:^FS
^FO50,180^A0N,40,40^FB700,5,0,L,0^FD${accEsc}^FS
^FO600,50^BQN,2,8
^FDQA,${serialNumber}^FS
^FO50,1050^A0N,30,30^FD${footer1}^FS
^FO50,1090^A0N,30,30^FD${footer2}^FS
${LOGO_GRF}
^XZ`;
}

// ── Serial expansion ──────────────────────────────────────────────────────────

/**
 * Expand a serial + quantity into an array of serials.
 * If the serial ends in digits, increments them across copies.
 * Otherwise repeats the same serial `quantity` times.
 *
 * @param {string} serial
 * @param {number} quantity
 * @returns {string[]}
 */
export function expandSerials(serial, quantity) {
  const match = serial.match(/^([\s\S]*?)(\d+)$/);
  if (!match) return Array(quantity).fill(serial);

  const prefix = match[1];
  const start  = parseInt(match[2], 10);
  const pad    = match[2].length;

  return Array.from({ length: quantity }, (_, i) =>
    `${prefix}${String(start + i).padStart(pad, '0')}`
  );
}
